#include<bits/stdc++.h>
using namespace std;
int cnt[1000010],c[200010],val[200010];
int blksiz;
struct node
{
    int l,r,id;
    bool operator<(const node&b)const
    {
        if(l/blksiz!=b.l/blksiz)
        {
            return l<b.l;
        }
        if((l/blksiz)%2==1)
        {
            return r<b.r;
        }
        return r>b.r;
    }
}q[200010];
long long res,ans[200010],cnt1[200010];
void add(int x)
{
    cnt1[cnt[c[x]]]--;
    cnt[c[x]]++;
    cnt1[cnt[c[x]]]++;
    res=max(res,1ll*cnt[c[x]]);
}
void del(int x)
{
    cnt1[cnt[c[x]]]--;
    cnt[c[x]]--;
    cnt1[cnt[c[x]]]++;
    if(res==cnt[c[x]]+1&&cnt1[cnt[c[x]]+1]==0)
    {
        res--;
    }
}
int main()
{
    int n,m;
    scanf("%d%d",&n,&m);
    blksiz=sqrt(n);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&c[i]);
        val[i]=c[i];
    }
    sort(val+1,val+1+n);
    int p=unique(val+1,val+1+n)-val-1;
    for(int i=1;i<=n;i++)
    {
        c[i]=lower_bound(val+1,val+1+p,c[i])-val;
    }
    for(int i=1;i<=m;i++)
    {
        scanf("%d%d",&q[i].l,&q[i].r);
        q[i].id=i;
    }
    sort(q+1,q+1+m);
    int l=1,r=0;
    for(int i=1;i<=m;i++)
    {
        while(l>q[i].l)
        {
            add(--l);
        }
        while(r<q[i].r)
        {
            add(++r);
        }
        while(l<q[i].l)
        {
            del(l++);
        }
        while(r>q[i].r)
        {
            del(r--);
        }
        ans[q[i].id]=res;
    }
    for(int i=1;i<=m;i++)
    {
        printf("%lld\n",-ans[i]);
    }
    return 0;
}
